/* eslint-disable no-unused-vars */
import {ArrowRight, CalendarDays, Camera, IndianRupee, PackagePlus, Pencil, Plus, ShoppingBag, Tags, Trash2} from 'lucide-react';
import {useEffect, useMemo, useState} from 'react';
import {Link, useNavigate, useParams} from 'react-router-dom';
import {Button, Card, Confirm, Empty, Field, PageHeader} from '../../components/UI';
import {useApp} from '../../lib/AppContext';
import {apiRequest, endpoints} from '../../lib/api';
import {bookingFormData, endOf, extractList, orderIdOf, orderProducts, productOf, productPublicId, startOf, todayInputValue, userIdOf} from '../../lib/dataHelpers';
import {asset} from '../../lib/demoData';


export function Categories() {
  const {session, localCategories, setLocalCategories, notify} = useApp(); const [name, setName] = useState(''); const [selected, setSelected] = useState(localCategories[0]?.catId || ''); const [image, setImage] = useState(null);
  useEffect(() => {apiRequest(endpoints.categories, {token: session.token}).then(response => {const categories = extractList(response); if (categories.length) {setLocalCategories(categories); setSelected(current => current || categories[0].catId || categories[0]._id || '');}}).catch(error => notify(error.message, 'error'));}, [session, setLocalCategories, notify]);
  const submit = async e => {e.preventDefault(); const isOther = selected === ''; const body = new FormData(); body.append('catName', isOther ? name : localCategories.find(item => (item.catId || item._id) === selected)?.catName || name); body.append('userId', userIdOf(session.user)); body.append('catId', selected); if (image) body.append('catImage', image); try {await apiRequest(endpoints.createCategory, {method: 'POST', token: session.token, body});} catch (error) {return notify(error.message, 'error');} const nextCategory = isOther ? {catId: `local-${Date.now()}`, catName: name, catImage: image ? URL.createObjectURL(image) : asset('image/Wedding.jpg')} : localCategories.find(item => (item.catId || item._id) === selected); if (nextCategory) setLocalCategories(items => items.some(item => (item.catId || item._id) === (nextCategory.catId || nextCategory._id)) ? items : [...items, nextCategory]); setName(''); setImage(null); notify(isOther ? 'Category created.' : 'Category added to vendor account.');};
  return <div className="page"><PageHeader eyebrow="Service range" title="Categories" text="Review available categories and add one to your vendor account." /><div className="split-layout"><section className="category-list">{localCategories.map(c => <Card key={c.catId || c._id}><img src={c.catImage || asset('image/Wedding.jpg')} alt="" /><strong>{c.catName}</strong></Card>)}</section><Card className="sticky-form"><Tags /><h2>Add category</h2><p>Select an existing mobile category or choose Other to create a new one.</p><form onSubmit={submit}><label className="field"><span>Category</span><select value={selected} onChange={e => setSelected(e.target.value)}>{localCategories.map(c => <option key={c.catId || c._id} value={c.catId || c._id}>{c.catName}</option>)}<option value="">Other</option></select></label>{selected === '' && <><Field label="Category name" required value={name} onChange={e => setName(e.target.value)} /><label className="upload-line"><Camera /><span><strong>Category image</strong><small>{image?.name || 'Choose image'}</small></span><input type="file" accept="image/*" onChange={e => setImage(e.target.files[0])} /></label></>}<Button>{selected === '' ? 'Create Category' : 'Add Category'}</Button></form></Card></div></div>;
}
